 1	import * as React from 'react';
 2	import { StatusType } from '@odf/ocs/constants';
 3	import HealthItem from '@odf/shared/dashboards/status-card/HealthItem';
 4	import { healthStateMapping } from '@odf/shared/dashboards/status-card/states';
 5	import { Status, StatusPopupSection } from '@odf/shared/popup/status-popup';
 6	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 7	import { getWorstStatus } from '@odf/shared/utils';
 8	import { HealthState } from '@openshift-console/dynamic-plugin-sdk';
 9	import { SubsystemHealth } from '@openshift-console/dynamic-plugin-sdk/lib/extensions/dashboard-types';
10	import { Stack, StackItem } from '@patternfly/react-core';
11	
12	type ObjectServiceStatusProps = {
13	  RGWMetrics: SubsystemHealth;
14	  MCGMetrics: SubsystemHealth;
15	  statusType: StatusType;
16	};
17	
18	export const ObjectServiceStatus: React.FC<ObjectServiceStatusProps> = ({
19	  RGWMetrics,
20	  MCGMetrics,
21	  statusType,
22	}) => {
23	  const { t } = useCustomTranslation();
24	
25	  const isMissing = !(RGWMetrics && MCGMetrics);
26	  const title =
27	    statusType === StatusType.HEALTH
28	      ? t('Object Service')
29	      : t('Data Resiliency');
30	  const popupTitle =
31	    statusType === StatusType.HEALTH
32	      ? t('Object Service Status')
33	      : t('Data Resiliency');
34	  const { state = HealthState.LOADING, message = '' } = !isMissing
35	    ? getWorstStatus([RGWMetrics, MCGMetrics], t)
36	    : {};
37	  return isMissing ? (
38	    <HealthItem
39	      title={title}
40	      state={RGWMetrics?.state || MCGMetrics?.state}
41	      details={RGWMetrics?.message || MCGMetrics?.message}
42	    />
43	  ) : (
44	    <HealthItem
45	      title={title}
46	      state={state}
47	      details={message}
48	      popupTitle={popupTitle}
49	    >
50	      <Stack hasGutter>
51	        <StackItem>
52	          {statusType === StatusType.HEALTH
53	            ? t('The object service includes 2 services.')
54	            : t('The data resiliency includes 2 services')}
55	        </StackItem>
56	        <StackItem>
57	          <StatusPopupSection
58	            firstColumn={t('Services')}
59	            secondColumn={t('Status')}
60	          >
61	            <Status icon={healthStateMapping[MCGMetrics.state]?.icon}>
62	              {t('Multicloud Object Gateway')}
63	            </Status>
64	            <Status icon={healthStateMapping[RGWMetrics.state]?.icon}>
65	              {t('Object Gateway (RGW)')}
66	            </Status>
67	          </StatusPopupSection>
68	        </StackItem>
69	      </Stack>
70	    </HealthItem>
71	  );
72	};

